{
  "domain_analysis": {
    "business_context": "A logistics platform managing the lifecycle of parcel deliveries, from creation through transit to final delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A parcel delivery unit tracked from creation to final delivery, identified by pickup and delivery addresses, with a measurable weight." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle stage of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing classification tier determined by the shipment's weight: Standard (0-10 kg), Heavy (10-50 kg), Freight (over 50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is logically meaningless — it represents corrupt data, not a policy choice. You cannot deliver a parcel if you don't know where to pick it up or where to bring it.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address OR delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "A shipment in the 'In Transit' state cannot transition back to 'Pending'.",
      "invariant": true,
      "invariant_justification": "This is a state integrity constraint. A parcel that is physically in transit cannot be un-dispatched — allowing this transition would make the system state inconsistent with physical reality.",
      "testable_assertion": "Calling a state-change operation that would move an In Transit shipment to Pending must be rejected with an error."
    },
    {
      "id": "BR-3",
      "rule": "A shipment in the 'Delivered' state is final — no further state transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Delivery is a terminal physical event. Once a parcel is handed to the recipient, the shipment record is a historical fact. Allowing state changes would corrupt audit trails and break downstream processes (invoicing, proof of delivery).",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment (to Pending, In Transit, or any other state) must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg.",
      "invariant": true,
      "invariant_justification": "A parcel with zero or negative weight is physically impossible and represents corrupt data, not a business decision.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Shipment weight must not exceed 1000 kg.",
      "invariant": false,
      "invariant_justification": "The 1000 kg cap is a business policy reflecting current fleet/infrastructure limits. A VP could raise this to 2000 kg if the company acquires heavier-duty vehicles. It is not a physical or data-integrity constraint.",
      "testable_assertion": "Creating or updating a shipment with weight > 1000 kg must be rejected under current policy."
    },
    {
      "id": "BR-6",
      "rule": "Weight bracket classification: Standard = (0, 10] kg, Heavy = (10, 50] kg, Freight = (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "Bracket boundaries are pricing policy. Management could change the thresholds (e.g., Standard up to 15 kg) without violating any physical or data-integrity constraint.",
      "testable_assertion": "A shipment with weight 10 kg is classified Standard; 10.01 kg is Heavy; 50 kg is Heavy; 50.01 kg is Freight."
    },
    {
      "id": "BR-7",
      "rule": "The only valid shipment state transitions are: Pending → In Transit, and In Transit → Delivered.",
      "invariant": true,
      "invariant_justification": "This is the implicit state machine derived from BR-2 and BR-3. Pending → Delivered (skipping transit) would misrepresent the physical process. State integrity requires the full sequence.",
      "testable_assertion": "A Pending shipment can only move to In Transit. An In Transit shipment can only move to Delivered. No other transitions are allowed."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A user provides a valid pickup address and a valid delivery address with a weight of 5 kg",
      "when": "The user creates a shipment",
      "then": "The shipment is created in 'Pending' state with weight bracket 'Standard'"
    },
    {
      "id": "AC-2",
      "given": "A user provides only a pickup address and no delivery address",
      "when": "The user attempts to create a shipment",
      "then": "The system rejects the request with a validation error indicating the delivery address is required"
    },
    {
      "id": "AC-3",
      "given": "A user provides only a delivery address and no pickup address",
      "when": "The user attempts to create a shipment",
      "then": "The system rejects the request with a validation error indicating the pickup address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment exists in the 'Pending' state",
      "when": "The shipment is moved to 'In Transit'",
      "then": "The shipment state is updated to 'In Transit'"
    },
    {
      "id": "AC-5",
      "given": "A shipment exists in the 'In Transit' state",
      "when": "An attempt is made to move it back to 'Pending'",
      "then": "The system rejects the transition with an error indicating irreversible state"
    },
    {
      "id": "AC-6",
      "given": "A shipment exists in the 'In Transit' state",
      "when": "The shipment is moved to 'Delivered'",
      "then": "The shipment state is updated to 'Delivered'"
    },
    {
      "id": "AC-7",
      "given": "A shipment exists in the 'Delivered' state",
      "when": "An attempt is made to change its state to any other state",
      "then": "The system rejects the transition with an error indicating delivered shipments are final"
    },
    {
      "id": "AC-8",
      "given": "A user provides a weight of 0 kg or a negative value",
      "when": "The user attempts to create a shipment",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A user provides a weight of 1001 kg",
      "when": "The user attempts to create a shipment",
      "then": "The system rejects the request indicating weight exceeds the 1000 kg maximum"
    },
    {
      "id": "AC-10",
      "given": "A shipment is created with a weight of exactly 10 kg",
      "when": "The system classifies the weight bracket",
      "then": "The shipment is classified as 'Standard'"
    },
    {
      "id": "AC-11",
      "given": "A shipment is created with a weight of 25 kg",
      "when": "The system classifies the weight bracket",
      "then": "The shipment is classified as 'Heavy'"
    },
    {
      "id": "AC-12",
      "given": "A shipment is created with a weight of 75 kg",
      "when": "The system classifies the weight bracket",
      "then": "The shipment is classified as 'Freight'"
    },
    {
      "id": "AC-13",
      "given": "A shipment exists in the 'Pending' state",
      "when": "An attempt is made to move it directly to 'Delivered'",
      "then": "The system rejects the transition — shipments must pass through 'In Transit' first"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard. The boundary belongs to the lower bracket (inclusive upper bound)." },
    { "scenario": "Weight is exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy. The boundary belongs to the lower bracket (inclusive upper bound)." },
    { "scenario": "Weight is exactly 1000 kg (max allowed)", "expected_behavior": "Accepted and classified as Freight." },
    { "scenario": "Weight is a very small positive number (e.g., 0.001 kg)", "expected_behavior": "Accepted and classified as Standard. The spec says 'positive,' which includes fractional values." },
    { "scenario": "Pickup address and delivery address are identical", "expected_behavior": "Ambiguous — spec does not forbid it, but this is logically suspicious. System should accept unless a business rule is added to prevent same-origin deliveries." },
    { "scenario": "Attempting to re-deliver an already Delivered shipment (e.g., re-attempt)", "expected_behavior": "Rejected. Delivered is terminal. A new shipment must be created for re-delivery or returns." },
    { "scenario": "Weight is exactly 0 kg", "expected_behavior": "Rejected. Weight must be strictly positive — zero is not a valid parcel weight." },
    { "scenario": "Concurrent state transitions (two actors both try to move Pending → In Transit)", "expected_behavior": "Only one should succeed. The system must enforce state transitions atomically to prevent inconsistency." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly determines pricing. Incorrect bracket assignment means revenue leakage (undercharging) or customer disputes (overcharging). The 1000 kg cap limits the addressable market to non-industrial shipments.",
    "operational": "The strict Pending → In Transit → Delivered state machine simplifies dispatch operations and prevents logistical confusion. Immutable delivered state ensures clean handoff to invoicing and proof-of-delivery processes.",
    "user": "Clear state transitions give senders and recipients predictable tracking. Validation at creation time (addresses, weight) prevents failed deliveries downstream.",
    "risk": "Boundary ambiguity on weight brackets (does 10 kg belong to Standard or Heavy?) could lead to systematic pricing errors across thousands of shipments if implemented incorrectly. The spec also does not address returns, cancellations, or partial deliveries — these gaps will surface as the platform grows.",
    "stakeholders_affected": [
      { "group": "Senders (shippers)", "impact": "Must provide valid addresses and weight at creation. Pricing transparency depends on correct bracket classification." },
      { "group": "Recipients", "impact": "Benefit from reliable state tracking. Delivered finality means no unexpected state regressions." },
      { "group": "Operations / Dispatch", "impact": "Strict state machine prevents re-dispatching or undoing pickups, simplifying workflow." },
      { "group": "Finance / Billing", "impact": "Weight brackets drive invoicing. Bracket boundary rules must be unambiguous to avoid billing disputes." },
      { "group": "Customer Support", "impact": "Delivered finality means they cannot 'undo' a delivery in the system — they need a separate returns or claims process." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on state machine rules and weight constraints, but leaves several domain questions unanswered: bracket boundary inclusivity (is 10 kg Standard or Heavy?), whether Pending → Delivered is forbidden, what constitutes a valid address, and no mention of cancellation, returns, or exception flows. I inferred boundary rules and the full state machine from logistics domain knowledge, but these should be confirmed with the PM.",
    "high_confidence_areas": [
      "State machine: Pending → In Transit → Delivered with no backward transitions",
      "Delivered is a terminal/final state",
      "Weight must be positive and ≤ 1000 kg",
      "Three weight brackets exist: Standard, Heavy, Freight",
      "Both pickup and delivery addresses are required at creation"
    ],
    "low_confidence_areas": [
      "Exact bracket boundary inclusivity (is 10 kg Standard or Heavy?) — I assumed inclusive upper bound but spec is ambiguous",
      "Whether Pending → Delivered (skipping In Transit) is allowed — spec only explicitly forbids In Transit → Pending",
      "Address validation requirements — spec says 'pickup address and delivery address' but not what makes an address valid",
      "Whether weight can be changed after shipment creation",
      "Initial state of a newly created shipment — assumed Pending but not explicitly stated"
    ],
    "assumptions": [
      "Newly created shipments start in the 'Pending' state",
      "Weight bracket boundaries are inclusive on the upper end (10 kg = Standard, 50 kg = Heavy)",
      "Pending → Delivered (skipping In Transit) is not allowed, based on logistics domain norms",
      "Weight is immutable after shipment creation (spec does not mention weight updates)",
      "The spec describes the complete set of valid states (no 'Cancelled', 'Failed', 'Returned' states)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundary inclusivity is not specified. Does a 10 kg shipment fall into Standard or Heavy? Does a 50 kg shipment fall into Heavy or Freight? The spec says '0-10 kg is standard, 10-50 kg is heavy, over 50 kg is freight' — the value 10 appears in both Standard and Heavy ranges.",
      "affected_stakeholders": ["Finance / Billing", "Senders (shippers)"],
      "options": [
        "A: Inclusive upper bound — 10 kg = Standard, 50 kg = Heavy (favors the customer, simpler mental model)",
        "B: Exclusive upper bound — 10 kg = Heavy, 50 kg = Freight (favors revenue)"
      ],
      "recommendation": "Option A (inclusive upper bound) — it aligns with common logistics industry practice and is more customer-friendly. But this must be confirmed with the PM to avoid systematic pricing errors."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not explicitly state whether a shipment can skip from Pending directly to Delivered. It only says 'once in transit, it cannot be sent back to pending' and 'delivered shipments are final.' A strict reading could allow Pending → Delivered.",
      "affected_stakeholders": ["Operations / Dispatch", "Finance / Billing"],
      "options": [
        "A: Allow Pending → Delivered (for edge cases like in-store pickup where transit is instant)",
        "B: Forbid Pending → Delivered — require the full Pending → In Transit → Delivered sequence"
      ],
      "recommendation": "Option B — standard logistics domain practice requires transit as a distinct phase. Skipping it would break tracking, SLA measurement, and carrier settlement. Confirm with PM."
    },
    {
      "type": "missing_context",
      "description": "The spec does not mention cancellation, returns, failed deliveries, or exception handling. In real logistics operations, these are common and critical flows. Without them, Customer Support has no system-supported way to handle problems.",
      "affected_stakeholders": ["Customer Support", "Senders (shippers)", "Recipients"],
      "options": [
        "A: Add a 'Cancelled' state reachable only from Pending",
        "B: Defer exception flows to a future iteration and document the gap"
      ],
      "recommendation": "Option B for now — build the happy path first, but document that cancellation and returns are known gaps that must be addressed before production launch."
    }
  ],

  "rejection_reasons": []
}

